 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly log10   (test_log10_opt.elf)
 *   2. Linked with toolchain's default log10        (test_log10_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += log10(vx);
#else
    double r = log10(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);                                   /* +0: log10(+0) = -Inf */
    emit(-0.0);                                  /* -0: log10(-0) = -Inf */
    emit_u(0x7ff8000000000000ULL);               /* qNaN */
    emit_u(0x7ff0000000000001ULL);               /* sNaN */
    emit_u(0xfff8000000000000ULL);               /* -qNaN */
    emit_u(0x7ff0000000000000ULL);               /* +Inf: log10(+Inf) = +Inf */
    emit_u(0xfff0000000000000ULL);               /* -Inf: log10(-Inf) = NaN (domain error) */

    /* --- Section 2: Domain errors - negative inputs (5) --- */
    emit_u(0xbff0000000000000ULL);               /* -1.0: domain error -> NaN */
    emit_u(0xc000000000000000ULL);               /* -2.0: domain error -> NaN */
    emit_u(0xbfe0000000000000ULL);               /* -0.5: domain error -> NaN */
    emit_u(0x8010000000000000ULL);               /* -DBL_MIN: domain error -> NaN */
    emit_u(0xffefffffffffffffULL);               /* -DBL_MAX: domain error -> NaN */

    /* --- Section 3: Subnormal (denormal) inputs (6) --- */
    emit_u(0x0000000000000001ULL);               /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);               /* min negative subnormal (domain error) */
    emit_u(0x0008000000000000ULL);               /* mid subnormal */
    emit_u(0x8008000000000000ULL);               /* mid negative subnormal (domain error) */
    emit_u(0x000fffffffffffffULL);               /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);               /* max negative subnormal (domain error) */

    /* --- Section 4: Normal boundary values (4) --- */
    emit(DBL_MIN);                               /* 2^-1022: smallest normal, log10 very negative */
    emit_u(0x0010000000000001ULL);               /* one ULP above DBL_MIN */
    emit(DBL_MAX);                               /* 0x7fefffffffffffff: largest normal */
    emit_u(0x7fefffffffffffffULL);               /* DBL_MAX itself (same, belt-and-suspenders) */

    /* --- Section 5: Near 1.0 - ULP density, log10 ~ 0 (8) --- */
    emit_u(0x3fefffffffffffffULL);               /* one ULP below 1.0 */
    emit(1.0);                                   /* 1.0: log10(1) = 0 exactly */
    emit_u(0x3ff0000000000001ULL);               /* one ULP above 1.0 */
    emit_u(0x3feffffffffffffe ULL);              /* two ULPs below 1.0 */
    emit_u(0x3ff0000000000002ULL);               /* two ULPs above 1.0 */
    emit_u(0x3feffffffffffff0ULL);               /* ~16 ULPs below 1.0 */
    emit_u(0x3ff0000000000010ULL);               /* ~16 ULPs above 1.0 */
    emit_u(0x3fefffffffffffc0ULL);               /* ~64 ULPs below 1.0 */

    /* --- Section 6: Exact powers of 10 - log10 yields integers (12) --- */
    emit(1.0e-6);                                /* log10 = -6 */
    emit(1.0e-5);                                /* log10 = -5 */
    emit(1.0e-4);                                /* log10 = -4 */
    emit(1.0e-3);                                /* log10 = -3 */
    emit(1.0e-2);                                /* log10 = -2 */
    emit(1.0e-1);                                /* log10 = -1 */
    emit(1.0e1);                                 /* log10 = 1 */
    emit(1.0e2);                                 /* log10 = 2 */
    emit(1.0e3);                                 /* log10 = 3 */
    emit(1.0e4);                                 /* log10 = 4 */
    emit(1.0e5);                                 /* log10 = 5 */
    emit(1.0e6);                                 /* log10 = 6 */

    /* --- Section 7: ULP neighbors of key powers of 10 (9) --- */
    emit_u(0x3fb999999999999aULL);               /* 0.1 = nearest double */
    emit_u(0x3fb9999999999999ULL);               /* one ULP below 0.1 */
    emit_u(0x3fb999999999999bULL);               /* one ULP above 0.1 */
    emit_u(0x4024000000000000ULL);               /* 10.0 exactly */
    emit_u(0x4023ffffffffffffULL);               /* one ULP below 10.0 */
    emit_u(0x4024000000000001ULL);               /* one ULP above 10.0 */
    emit_u(0x4059000000000000ULL);               /* 100.0 exactly */
    emit_u(0x4058ffffffffffffULL);               /* one ULP below 100.0 */
    emit_u(0x4059000000000001ULL);               /* one ULP above 100.0 */

    /* --- Section 8: Key mathematical constants (10) --- */
    emit(M_E);                                   /* e ~ 2.718: log10(e) = log10e */
    emit(M_LN2);                                 /* ln(2) ~ 0.693 */
    emit(M_LN10);                                /* ln(10) ~ 2.303: log10(ln10) */
    emit(M_PI);                                  /* pi ~ 3.14159 */
    emit(3.162277660168379332);                  /* sqrt(10): log10 = 0.5 exactly */
    emit(31.62277660168379332);                  /* 10^1.5: log10 = 1.5 */
    emit(316.2277660168379332);                  /* 10^2.5: log10 = 2.5 */
    emit(0.31622776601683793);                   /* 10^-0.5: log10 = -0.5 */
    emit_u(0x3fe62e42fefa39efULL);               /* ln(2): log10(ln2) */
    emit_u(0x400a934f0979a371ULL);               /* ln(10): double bit pattern */

    /* --- Section 9: Powers of 2 - exponent switching points (10) --- */
    emit(0.25);                                  /* 2^-2 */
    emit(0.5);                                   /* 2^-1 */
    emit(2.0);                                   /* 2^1 */
    emit(4.0);                                   /* 2^2 */
    emit(8.0);                                   /* 2^3 */
    emit(16.0);                                  /* 2^4 */
    emit(32.0);                                  /* 2^5 */
    emit(64.0);                                  /* 2^6 */
    emit(1024.0);                                /* 2^10 */
    emit(1048576.0);                             /* 2^20 */

    /* --- Section 10: Near-1.0 catastrophic cancellation (10) --- */
    emit(1.0 + 1.0e-15);                         /* 1 + tiny: log10 ~ x/ln10 */
    emit(1.0 - 1.0e-15);                         /* 1 - tiny: log10 ~ -x/ln10 */
    emit(1.0 + 1.0e-10);                         /* moderate offset above 1 */
    emit(1.0 - 1.0e-10);                         /* moderate offset below 1 */
    emit(1.0 + 1.0e-6);                          /* larger offset above 1 */
    emit(1.0 - 1.0e-6);                          /* larger offset below 1 */
    emit(1.0 + 1.0e-3);                          /* small but meaningful offset */
    emit(1.0 - 1.0e-3);
    emit(1.0 + 1.0e-1);                          /* 1.1 */
    emit(1.0 - 1.0e-1);                          /* 0.9 */

    /* --- Section 11: Large and small value spread (13) --- */
    emit(1.0e-300);                              /* extremely small: log10 ~ -300 */
    emit(1.0e-200);
    emit(1.0e-100);
    emit(1.0e-50);
    emit(1.0e-20);
    emit(1.0e-10);
    emit(5.0);                                   /* log10(5) = 1 - log10(2) */
